using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) Strongly-typed retrieval — returns JsonTypeInfo<Person> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type      : {personInfo.Type.Name}");
Console.WriteLine($"Kind      : {personInfo.Kind}");
Console.WriteLine($"Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");
Console.WriteLine();

// 2) Probe without throwing — TryGetTypeInfo returns false when metadata
//    isn't available instead of throwing InvalidOperationException.
//    With the default resolver this succeeds for any public type...
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Probe Person  : found ({found!.Type.Name})");
else
    Console.WriteLine("Probe Person  : not found");

// ...but if we use a custom resolver that only knows about Person,
// the probe for an unregistered type returns false instead of throwing.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // Accept only Person metadata; strip everything else.
            if (ti.Type != typeof(Person))
                ti.Properties.Clear();
        })
};

// Int32 metadata still "resolves" (the resolver doesn't throw for it),
// so let's show a truly absent case: use a resolver that explicitly
// returns null for non-Person types.
var strict = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new PersonOnlyResolver())
};

if (strict.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? p2))
    Console.WriteLine($"Strict Person : found ({p2!.Type.Name})");
else
    Console.WriteLine("Strict Person : not found");

if (strict.TryGetTypeInfo(typeof(int), out _))
    Console.WriteLine("Strict int    : found");
else
    Console.WriteLine("Strict int    : not found  (no exception thrown!)");

// --- helper types --------------------------------------------------------

record Person(string Name, int Age);

/// A resolver that only provides metadata for <see cref="Person"/>.
sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) =>
        type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

